[
  {
    "noteId": "n01",
    "kind": "change-order",
    "targets": ["script#beat-04", "page/beat-04", "doc"],
    "changeType": "content+structure+voice",
    "interpretation": "Add an explicit bridge when the example moves from songs to resumes so it reads as the same meter visiting a new aisle (not a topic change), mirror the bridge in the doc, and rework the walk-home / cheapest-fix prediction question so it lands naturally at the close instead of feeling bolted on.",
    "confidence": "high",
    "miss": { "critic": "vera", "artifact": "script/beat-04" }
  },
  {
    "noteId": "n02",
    "kind": "change-order",
    "targets": ["ix/dot-alignment", "storyboard#beat-02"],
    "changeType": "visual+content+voice+scope",
    "interpretation": "Rebuild the dot-alignment interactive to brand spec (thin exact strokes, proportional arrowhead on the amber probe, labels like 'probe 90' that never collide with candidate arrows); add a candidate-length control alongside probe direction so the learner feels direction move the score while length cheats it (the session's second conflict); and replace the vague 'call it' / 'Before you drag anything, call it:' prompt with a concrete prediction ask (name which candidate tops out before touching the probe), fixing this phrasing wherever it appears.",
    "alternative": "Treat only the visual cleanup and prompt rewording as in-scope and defer the length-control feature as a larger interactive rebuild.",
    "confidence": "medium",
    "miss": { "critic": "iris", "artifact": "ix/dot-alignment" }
  },
  {
    "noteId": "n03",
    "kind": "change-order",
    "targets": ["spine", "storyboard#beat-01", "storyboard#beat-02"],
    "changeType": "structure+content+scope",
    "interpretation": "SPINE-LEVEL, pauses the round for sign-off: restructure the opening so the difficulty of comparing many-featured things is posed as a puzzle the reader actually attempts before the dot product is handed over as the resolution (light, judgment-limited touch on why many features make comparison painful), so the aha feels earned rather than announced.",
    "confidence": "high",
    "miss": { "critic": "petra", "artifact": "spine.md" }
  },
  {
    "noteId": "n04",
    "kind": "style-amendment",
    "confidence": "high",
    "miss": { "critic": "none" },
    "styleAmendment": {
      "rule": "Pose the problem as a puzzle the reader has genuinely tried before revealing the mechanism, and let the answer arrive as a resolution; never open with 'here is the trick.'",
      "rationale": "Generalizes the earned-aha structure across every session, making the arc a repeatable pedagogical contract rather than a one-off fix to dotprod."
    }
  },
  {
    "noteId": "n05",
    "kind": "style-amendment",
    "confidence": "high",
    "miss": { "critic": "none" },
    "styleAmendment": {
      "rule": "Write every prediction prompt as a concrete ask the learner can actually answer (e.g. 'say which candidate tops out'), never a vague imperative like 'call it.'",
      "rationale": "Prediction prompts recur in interactives and storyboards across sessions; requiring answerable specificity generalizes beyond this interactive's broken 'call it' line."
    }
  },
  {
    "noteId": "n06",
    "kind": "style-amendment",
    "confidence": "high",
    "miss": { "critic": "none" },
    "styleAmendment": {
      "rule": "Never switch analogy domains mid-session without an explicit bridge sentence naming that it is the same structure in a new setting.",
      "rationale": "Domain jumps read as topic changes whenever they happen; a mandatory bridge sentence generalizes the fix beyond the dotprod songs-to-resumes switch."
    }
  }
]

